cypher:
MATCH (per:Person)-[:AFFILIATED_WITH]->(o:Organization)
WHERE NOT EXISTS { MATCH (:Patent)-[:APPLIED_BY]->(o) }
  AND NOT EXISTS { MATCH (:Patent)-[:OWNED_BY]->(o) }
RETURN per.name AS person, o.name AS org
ORDER BY org, person
LIMIT 30

MATCH (p:Patent)
WHERE EXISTS { MATCH (p)-[:CLASSIFIED_AS]->(i1:IPCCode) WHERE i1.code STARTS WITH 'H01M' }
  AND EXISTS { MATCH (p)-[:CLASSIFIED_AS]->(i2:IPCCode) WHERE i2.code STARTS WITH 'C25B' }
RETURN p.application_no AS application_no, p.title AS title
ORDER BY application_no
LIMIT 20

MATCH (p:Patent)
WHERE EXISTS { MATCH (p)-[:CLASSIFIED_AS]->(i1:IPCCode) WHERE i1.code STARTS WITH 'C01B' }
  AND EXISTS { MATCH (p)-[:CLASSIFIED_AS]->(i2:IPCCode) WHERE i2.code STARTS WITH 'B01J' }
RETURN p.application_no AS application_no, p.title AS title
ORDER BY application_no
LIMIT 20
